example.code:
map $http_upgrade $connection_upgrade {
    default upgrade;
    ''      close;
}

server {
    listen 80;
    listen 443 ssl;
    server_name nero.faion.net;

    ssl_certificate     /etc/nginx/ssl/cloudflare-origin.pem;
    ssl_certificate_key /etc/nginx/ssl/cloudflare-origin-key.pem;

    add_header Strict-Transport-Security "max-age=63072000; includeSubDomains" always;
    add_header X-Content-Type-Options "nosniff" always;
    add_header Content-Security-Policy "default-src 'self'; connect-src 'self' wss://nero.faion.net; frame-ancestors https://*.telegram.org;" always;

    location /api/ {
        rewrite ^/api/(.*) /$1 break;
        include snippets/proxy-params.conf;
        proxy_pass http://127.0.0.1:8100;
    }

    location /health {
        include snippets/proxy-params.conf;
        proxy_pass http://127.0.0.1:8100;
    }

    location /ws {
        include snippets/proxy-params.conf;
        include snippets/websocket.conf;
        proxy_pass http://127.0.0.1:8100;
    }

    location /internal-attachments/ {
        internal;
        alias /srv/nero/attachments/;
    }

    location / {
        include snippets/proxy-params.conf;
        proxy_pass http://127.0.0.1:8101;
    }
}

server {
    listen 80;
    server_name meetingtax.io www.meetingtax.io;
    root /var/www/meetingtax;
    index index.html;
    location / { try_files $uri $uri/ /index.html; }
}

server {
    listen 80;
    server_name app.meetingtax.io;
    include snippets/security-headers.conf;

    location /api/ {
        rewrite ^/api/(.*) /$1 break;
        include snippets/proxy-params.conf;
        proxy_pass http://127.0.0.1:8000;
    }
    location /ws {
        include snippets/proxy-params.conf;
        include snippets/websocket.conf;
        proxy_pass http://127.0.0.1:8000;
    }
    location / {
        include snippets/proxy-params.conf;
        proxy_pass http://127.0.0.1:3000;
    }
}

server {
    listen 80;
    server_name api.meetingtax.io;
    include snippets/security-headers.conf;
    location / {
        include snippets/proxy-params.conf;
        proxy_pass http://127.0.0.1:8000;
        limit_req zone=api_general burst=20 nodelay;
    }
}

sudo tee /etc/nginx/sites-available/newsite.example.com << 'NGINX'
server {
    listen 80;
    server_name newsite.example.com;
    include snippets/security-headers.conf;
    client_max_body_size 10M;

    location /api/ {
        rewrite ^/api/(.*) /$1 break;
        include snippets/proxy-params.conf;
        proxy_pass http://127.0.0.1:8200;
    }

    location / {
        include snippets/proxy-params.conf;
        proxy_pass http://127.0.0.1:3200;
    }
}
NGINX

sudo ln -sf /etc/nginx/sites-available/newsite.example.com /etc/nginx/sites-enabled/
sudo nginx -t && sudo systemctl reload nginx
